# Tmkeen Design System — Windows Installer
# Usage: powershell -ExecutionPolicy Bypass -File install-design-system.ps1

$DestRoot = "C:\Users\asama\Projects\itsalplatform.zaad"
$ZipPath  = Join-Path $env:TEMP "design-system.zip"
$DestDir  = Join-Path $DestRoot "design-system"

New-Item -ItemType Directory -Force -Path $DestRoot | Out-Null

$b64 = @"

"@

[IO.File]::WriteAllBytes($ZipPath, [Convert]::FromBase64String($b64))
Expand-Archive -Path $ZipPath -DestinationPath $DestRoot -Force
Remove-Item $ZipPath -Force

Write-Host "Done: $DestDir" -ForegroundColor Green
Get-ChildItem $DestDir -Recurse | Select-Object FullName
